export class WebSocketError extends Error{code;details;constructor(message,code,details){super(message),this.code=code,this.details=details,this.name="WebSocketError"}}export class ConnectionError extends WebSocketError{constructor(message,details){super(message,"CONNECTION_ERROR",details),this.name="ConnectionError"}}export class RequestTimeoutError extends WebSocketError{constructor(message,details){super(message,"REQUEST_TIMEOUT",details),this.name="RequestTimeoutError"}}export class NoConnectionError extends WebSocketError{constructor(message="No Figma plugin connection available"){super(message,"NO_CONNECTION"),this.name="NoConnectionError"}}